document.addEventListener("DOMContentLoaded",function(){var h=document.querySelector(".hero-banner");if(h&&typeof Glide!=="undefined"){new Glide(".hero-banner",{type:"slider",autoplay:false,hoverpause:true,perView:1}).mount();}var ag=document.querySelector(".announcement-glide");if(ag&&typeof Glide!=="undefined"){new Glide(".announcement-glide",{type:"slider",autoplay:8000,animationDuration:1000,perView:1,hoverpause:true}).mount();}var cb=document.getElementById("announcement-close"),ab=document.getElementById("announcement-bar");if(cb&&ab){cb.addEventListener("click",function(){ab.classList.add("opacity-0","-translate-y-full");ab.classList.remove("opacity-100","translate-y-0");setTimeout(function(){ab.style.display="none";},500);});}});document.addEventListener("DOMContentLoaded",function(){document.addEventListener("click",function(t){const e=t.target.closest(".qty-decrement"),n=t.target.closest(".qty-increment");if(e||n){const t=(e||n).closest(".qty-selector");if(!t)return;const r=t.querySelector('input[name="quantity"]');if(!r)return;let c=parseInt(r.value,10);isNaN(c)&&(c=1),e?c=Math.max(1,c-1):c+=1,r.value=String(c)}})}),window.applyHoverImages=function(){try{window.matchMedia&&window.matchMedia("(hover: hover) and (pointer: fine)").matches&&document.querySelectorAll("img[data-hover-src]").forEach(function(t){t.getAttribute("src")||t.setAttribute("src",t.getAttribute("data-hover-src"))})}catch(t){}},document.addEventListener("DOMContentLoaded",function(){try{window.applyHoverImages()}catch(t){}});